def verifyJWT(jwt):
    try:
        # Decode the JWT using the secret key
        decoded = jwtDecode(jwt, 'secret')

        # Get the payload from the JWT token
        payload = decoded['payload']

        # Check if the payload contains a timestamp field
        if 'timestamp' in payload:
            # Convert the timestamp to datetime object
            timestamp = datetime.fromtimestamp(payload['timestamp'])

            # Calculate the current time and compare it with the timestamp
            currentTime = datetime.now()
            diff = (currentTime - timestamp).total_seconds() / 60

            # Check if the difference between the current time and the timestamp is less than or equal to 5 minutes
            if abs(diff) <= 5:
                print('JWT verified successfully!')
            else:
                print('JWT verification failed! Timestamp expired.')
        else:
            print('JWT verification failed! Missing timestamp field in payload.')
    except Exception as e:
        # Handle any exceptions that may occur during decoding or printing
        print('Error while verifying JWT:', str(e))

